App.Http.DocumentTemplatesSettings={store:function(t){const e=App.Utils.Url.siteUrl("document_templates_settings/store");return t.append("csrf_token",vars("csrf_token")),$.ajax({url:e,type:"POST",data:t,processData:!1,contentType:!1})},update:function(t){const e=App.Utils.Url.siteUrl("document_templates_settings/update");return t.append("csrf_token",vars("csrf_token")),$.ajax({url:e,type:"POST",data:t,processData:!1,contentType:!1})},destroy:function(t){const e=App.Utils.Url.siteUrl("document_templates_settings/destroy"),s={csrf_token:vars("csrf_token"),template_id:t};return $.post(e,s)}};